import java.util.Scanner;

public class SecureBufferExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        // Ensure that the buffer size matches the input length or limit it to a safe maximum
        int bufferSize = Math.min(name.length(), 10); // Limit buffer size to a safe maximum
        char[] buffer = new char[bufferSize];

        // Copy only up to bufferSize characters from input to buffer
        name.getChars(0, bufferSize, buffer, 0);

        System.out.println("Hello, " + new String(buffer));
    }
}

